// ============================================================================
// NANO BANANA PRO - PROMPT ENHANCER (V2)
// Enrichit le prompt pour Gemini Image Generation
// ============================================================================

const input = $input.first().json;

// Parametres d'entree
const userPrompt = input.positive_prompt || input.prompt || 'Modern minimalist marketing visual';
const aspectRatio = input.aspect_ratio || '1:1';
const style = input.style || 'minimalist, tech, premium';
const brandColors = input.brand_colors || '#000000, #FFFFFF, #FF00FF, #00FFFF';

// Determiner la taille
let size = '1024x1024'; // Default: 1:1
if (aspectRatio === '9:16' || aspectRatio === '9/16') {
  size = '1024x1792'; // Portrait/Story
} else if (aspectRatio === '16:9' || aspectRatio === '16/9') {
  size = '1792x1024'; // Landscape
}

// Enrichir le prompt avec le style The Hive
const enhancedPrompt = `${userPrompt}

STYLE REQUIREMENTS:
- Ultra high quality, 8K resolution
- ${style}
- Color palette: ${brandColors}
- Dark background (black or deep slate)
- Neon accents and glow effects
- Clean composition with 30% negative space
- Professional marketing aesthetic
- NO text, NO watermarks, NO logos
- Photorealistic lighting with dramatic shadows`;

return [{
  json: {
    enhanced_prompt: enhancedPrompt,
    original_prompt: userPrompt,
    size: size,
    aspect_ratio: aspectRatio,
    style: style
  }
}];

// ============================================================================
// NANO BANANA PRO - OUTPUT FORMATTER (V3 - GEMINI + FILE.IO)
// Pour Gemini image generation avec upload file.io
// ============================================================================

const fileioResponse = $input.first().json;
let enhancerData = {};

// Recuperer les donnees du node Enhance Prompt
try {
  enhancerData = $('Enhance Prompt').first().json;
} catch (e) {
  enhancerData = { enhanced_prompt: '', original_prompt: '', size: '1024x1024' };
}

// Extraire l'URL de file.io
// file.io retourne: { success: true, key: "abc123", link: "https://file.io/abc123" }
const imageUrl = fileioResponse.link || fileioResponse.url || null;

if (!imageUrl) {
  return [{
    json: {
      success: false,
      tool: 'nano_banana_pro',
      error: 'Upload failed: ' + JSON.stringify(fileioResponse),
      image: null,
      image_url: null,
      generated_at: new Date().toISOString()
    }
  }];
}

// Structure de sortie pour l'Agent Principal
return [{
  json: {
    success: true,
    tool: 'nano_banana_pro',
    image: {
      url: imageUrl,
      prompt_used: enhancerData.enhanced_prompt || '',
      original_prompt: enhancerData.original_prompt || '',
      size: enhancerData.size || '1024x1024',
      aspect_ratio: enhancerData.aspect_ratio || '1:1',
      style: enhancerData.style || 'minimalist, tech, premium',
      model: 'gemini-2.0-flash-exp-image-generation',
      quality: 'hd',
      expires: fileioResponse.expires || '14 days',
      file_key: fileioResponse.key || null
    },
    // IMPORTANT: image_url au niveau racine pour faciliter l'extraction
    image_url: imageUrl,
    generated_at: new Date().toISOString()
  }
}];

// ============================================================================
// ERROR HANDLER - Format error response
// ============================================================================

const error = $input.first().json;

return [{
  json: {
    success: false,
    tool: 'nano_banana_pro',
    error: {
      message: error.message || 'Image generation failed',
      details: JSON.stringify(error)
    },
    image: null,
    image_url: null,
    generated_at: new Date().toISOString()
  }
}];
